// Delete a node when you have pointer to it - O(1)
void deleteNode(struct Node *node) {
 if(node == NULL) return;

 // If node is head
 if(node == head) {
 head = node->next;
 }

 // If node is tail
 if(node == tail) {
 tail = node->prev;
 }

 // Update prev node's next
 if(node->prev != NULL) {
 node->prev->next = node->next;
 }

 // Update next node's prev
 if(node->next != NULL) {
 node->next->prev = node->prev;
 }

 free(node);
}

// In singly linked list, this would be O(n)
// because we'd need to find the previous node

def delete_node(self, node):
 if node is None:
 return

 # If node is head
 if node == self.head:
 self.head = node.next

 # If node is tail
 if node == self.tail:
 self.tail = node.prev

 # Update prev node's next
 if node.prev:
 node.prev.next = node.next

 # Update next node's prev
 if node.next:
 node.next.prev = node.prev

public void deleteNode(Node node) {
 if(node == null) return;

 if(node == head) {
 head = node.next;
 }

 if(node == tail) {
 tail = node.prev;
 }

 if(node.prev != null) {
 node.prev.next = node.next;
 }

 if(node.next != null) {
 node.next.prev = node.prev;
 }
}

// Insert before a given node - O(1)
void insertBefore(struct Node *node, int data) {
 if(node == NULL) return;

 struct Node *newNode = createNode(data);

 newNode->next = node;
 newNode->prev = node->prev;

 if(node->prev != NULL) {
 node->prev->next = newNode;
 } else {
 head = newNode; // Inserted before head
 }

 node->prev = newNode;
}

// In singly linked list, this is O(n)
// because we need to traverse to find previous node

def insert_before(self, node, data):
 if node is None:
 return

 new_node = Node(data)
 new_node.next = node
 new_node.prev = node.prev

 if node.prev:
 node.prev.next = new_node
 else:
 self.head = new_node

 node.prev = new_node

public void insertBefore(Node node, int data) {
 if(node == null) return;

 Node newNode = new Node(data);
 newNode.next = node;
 newNode.prev = node.prev;

 if(node.prev != null) {
 node.prev.next = newNode;
 } else {
 head = newNode;
 }

 node.prev = newNode;
}

void reverse() {
 struct Node *current = head;
 struct Node *temp = NULL;

 // Swap prev and next for each node
 while(current != NULL) {
 temp = current->prev;
 current->prev = current->next;
 current->next = temp;

 // Move to next node (which is now prev)
 current = current->prev;
 }

 // Swap head and tail
 temp = head;
 head = tail;
 tail = temp;
}

public void reverse() {
 Node current = head;
 Node temp = null;

 while(current != null) {
 temp = current.prev;
 current.prev = current.next;
 current.next = temp;
 current = current.prev;
 }

 temp = head;
 head = tail;
 tail = temp;
}
